mapper.select:
SELECT pd.location, COUNT(*) as alarmCount FROM power_monitor_record pmr JOIN power_device pd ON pmr.device_id = pd.id WHERE pmr.is_alarm = 1
AND pmr.collect_time >= #{startTime}
AND pmr.collect_time <= #{endTime}
AND pmr.tenant_id = #{tenantId}
GROUP BY pd.location

SELECT pmr.alarm_level as alarmLevel, COUNT(*) as alarmCount FROM power_monitor_record pmr WHERE pmr.is_alarm = 1
AND pmr.collect_time >= #{startTime}
AND pmr.collect_time <= #{endTime}
AND pmr.tenant_id = #{tenantId}
GROUP BY pmr.alarm_level
